import{_ as a,o as t,c as i,a2 as s}from"./chunks/framework.CHeM0PsO.js";const u=JSON.parse('{"title":"RFC 0070 — Per-user capability grants","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0070-per-user-capability-grants.md","filePath":"rfcs/0070-per-user-capability-grants.md"}'),o={name:"rfcs/0070-per-user-capability-grants.md"};function r(n,e,l,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="rfc-0070-—-per-user-capability-grants" tabindex="-1">RFC 0070 — Per-user capability grants <a class="header-anchor" href="#rfc-0070-—-per-user-capability-grants" aria-label="Permalink to &quot;RFC 0070 — Per-user capability grants&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> July 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>runtime/src/capabilities.ts</code>, <code>packages/db</code>, <code>runtime/src/session-verify.ts</code>, <code>runtime/middleware.ts</code>, <code>packages/sdk</code> (<code>hasCapability</code>), Console (capability grant UI), docs; builds on RFC 0021 (platform roles &amp; capabilities); is a dependency of RFC 0065 (self-service plugin access)<br><strong>Incorporated into plan:</strong> Yes — epic task 1.16. Roadmap slot deferred; prioritized within plugins-runtime alongside RFC 0065.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Add a narrow per-user capability override on top of RFC 0021&#39;s role-preset model: an owner/admin can grant one specific user a single named capability their role preset doesn&#39;t include, without changing that user&#39;s role or defining a new custom role. The first consumer is RFC 0065&#39;s plugin self-service opt-in (<code>plugins:self-manage</code>), but the mechanism is general — RFC 0021 already anticipated this exact gap and designed the model to accommodate it &quot;without a schema change.&quot;</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>RFC 0065 wants a specific, narrow permission: let an operator decide that certain users may turn plugins on/off for themselves (within whatever they&#39;re already eligible for), without making those users admins and without inventing a new role for what might be one or two people. Today that&#39;s not expressible — <code>hasCapability(role, cap)</code> (<code>runtime/src/capabilities.ts:117</code>) is a pure function of role alone, with no per-user dimension, by design (RFC 0021&#39;s Edge-gate constraint: capabilities must be derivable offline from the signed session cookie).</p><p>RFC 0021 explicitly flagged this as future work: &quot;Override granularity — per-role redefinition vs per-user grants/revokes vs both — is an open question; the resolver is designed for both&quot; (RFC 0021 §&quot;DB-driven override&quot;), and separately lists &quot;per-user overrides remain a later phase on top of the same resolver&quot; in its adoption path. This RFC is that later phase — scoped narrowly to grants (adding a capability a role doesn&#39;t have), not full per-user capability redefinition.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><code>runtime/src/capabilities.ts:107-119</code> — <code>capabilitiesForRole(role)</code> / <code>hasCapability(role, cap)</code> take a bare role string, no user ID. <code>ROLE_PRESETS</code> (line 91) is a static <code>Record&lt;PlatformRole, Set&lt;Capability&gt;&gt;</code>.</li><li>Capabilities are carried in the signed <code>session_data</code> cookie cache alongside <code>role</code> (RFC 0021 &quot;The Edge-gate wrinkle&quot;), computed server-side and read offline by Edge middleware. This is the load-bearing constraint any per-user mechanism must respect.</li><li>No <code>user_capability_grants</code> table or equivalent exists. There is no code path today that checks &quot;does this specific user (regardless of role) have capability X.&quot;</li><li>RFC 0065 needs exactly one such check (<code>plugins:self-manage</code>) to gate the self-service plugin opt-in described in its &quot;Self-service opt-in&quot; section.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="grant-model" tabindex="-1">Grant model <a class="header-anchor" href="#grant-model" aria-label="Permalink to &quot;Grant model&quot;">​</a></h3><p>Add a <code>user_capability_grants</code> table:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>user_capability_grants(</span></span>
<span class="line"><span>  tenant_id,</span></span>
<span class="line"><span>  user_id,</span></span>
<span class="line"><span>  capability,</span></span>
<span class="line"><span>  granted_by_user_id,</span></span>
<span class="line"><span>  granted_at</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>A row grants exactly one additional capability to one user, additively on top of their role preset — this RFC does not support revoking a capability a role preset already includes. If that need arises later (e.g. a custom admin missing one specific capability) it&#39;s a natural extension of this table (an explicit deny row), not a redesign, but is out of scope here.</p><h3 id="resolution" tabindex="-1">Resolution <a class="header-anchor" href="#resolution" aria-label="Permalink to &quot;Resolution&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>effectiveCapabilities(user):</span></span>
<span class="line"><span>  base = capabilitiesForRole(user.role)</span></span>
<span class="line"><span>  grants = user_capability_grants for user.id</span></span>
<span class="line"><span>  return base ∪ grants</span></span></code></pre></div><p><code>hasCapability</code> keeps its existing offline, role-only signature for Edge middleware use — that code path is unaffected. A new <code>hasUserCapability(user, cap)</code> (or an overload taking an optional grant set) is added for the Node-runtime call sites that need the per-user check, mirroring how RFC 0021 already separates Edge-safe role checks from richer Node-runtime checks.</p><h3 id="session-cache-propagation" tabindex="-1">Session cache propagation <a class="header-anchor" href="#session-cache-propagation" aria-label="Permalink to &quot;Session cache propagation&quot;">​</a></h3><p>Following RFC 0021&#39;s existing pattern exactly: a user&#39;s effective capabilities (role preset ∪ grants) are computed server-side at session-verify time and carried in the signed <code>session_data</code> cookie cache alongside the existing capability list, so Edge middleware continues to read everything it needs offline with no DB round-trip. Staleness is bounded by the existing cookie-cache <code>maxAge</code> (300s) — identical trade-off to a role change today. No new cache invalidation mechanism is introduced.</p><h3 id="scope-of-what-can-be-granted" tabindex="-1">Scope of what can be granted <a class="header-anchor" href="#scope-of-what-can-be-granted" aria-label="Permalink to &quot;Scope of what can be granted&quot;">​</a></h3><p>Not every capability is a sensible per-user grant target. <code>role:assign</code> (owner-only, RFC 0021) must remain excluded from this mechanism — granting role-assignment power to an individual user outside the role system would undermine the owner-protection guarantee RFC 0021 established. The grantable set is an explicit allowlist starting with <code>plugins:self-manage</code> (added by this RFC as a new <code>Capability</code> value, not present in any role preset by default), extensible as concrete needs arise.</p><h3 id="console-ux" tabindex="-1">Console UX <a class="header-anchor" href="#console-ux" aria-label="Permalink to &quot;Console UX&quot;">​</a></h3><p>A capability grant UI, scoped to the grantable-capability allowlist:</p><ul><li>On a user&#39;s Console detail page, an admin/owner can add/remove individual capability grants for that user, from the allowlist only (not an open-ended capability picker).</li><li>Grants are audited (RFC 0005), attributed to the granting admin.</li><li>Effective capabilities (role preset + grants) are shown together so it&#39;s clear a grant is an addition on top of the role, not a role change.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="full-per-user-rbac-arbitrary-capability-redefinition-per-user" tabindex="-1">Full per-user RBAC / arbitrary capability redefinition per user <a class="header-anchor" href="#full-per-user-rbac-arbitrary-capability-redefinition-per-user" aria-label="Permalink to &quot;Full per-user RBAC / arbitrary capability redefinition per user&quot;">​</a></h3><p>Rejected for the same reason RFC 0021 rejected it for v1: the SRS and RFC 0021 both scope this as a later, narrower phase — additive grants, not a general override/redefinition system. A full system multiplies the surface that has to reason about &quot;why does this user have this capability&quot; without a concrete need beyond the one RFC 0065 has today.</p><h3 id="a-dedicated-one-off-boolean-on-the-user-record-e-g-canselfmanageplugins" tabindex="-1">A dedicated one-off boolean on the user record (e.g. <code>canSelfManagePlugins</code>) <a class="header-anchor" href="#a-dedicated-one-off-boolean-on-the-user-record-e-g-canselfmanageplugins" aria-label="Permalink to &quot;A dedicated one-off boolean on the user record (e.g. \`canSelfManagePlugins\`)&quot;">​</a></h3><p>Rejected — it solves RFC 0065&#39;s immediate need but doesn&#39;t generalize, and RFC 0021 already designed the resolver to support per-user grants without a schema change; a bespoke boolean would be exactly the kind of ad hoc field that mechanism was meant to avoid.</p><h3 id="custom-roles-instead-of-per-user-grants" tabindex="-1">Custom roles instead of per-user grants <a class="header-anchor" href="#custom-roles-instead-of-per-user-grants" aria-label="Permalink to &quot;Custom roles instead of per-user grants&quot;">​</a></h3><p>An owner could already create a custom role (RFC 0021&#39;s DB-driven override, per-role redefinition) with <code>plugins:self-manage</code> added, and assign specific users to it. This remains a valid path for larger groups of users who need the same override, and doesn&#39;t require this RFC. Per-user grants are for the case a custom role is overkill for — one or two individuals, or an exception that doesn&#39;t warrant a new role in the role list. The two mechanisms are complementary, not competing.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ul><li>Should grants ever be group-scoped (grant a capability to every member of a RFC 0065 user group) rather than strictly per-user? Deferred — per-user is sufficient for the immediate <code>plugins:self-manage</code> need, and group-scoped grants can be layered on later by resolving group membership at the same point role presets are resolved.</li><li>Should the grantable-capability allowlist be config-driven (operator-extensible) or hardcoded per release? Leaning hardcoded for v1, consistent with RFC 0021&#39;s hardcoded-preset philosophy — revisit if real operator demand appears for granting other capabilities individually.</li></ul><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Add <code>user_capability_grants</code> table and the allowlist-gated resolver.</li><li>Extend session-verify to fold grants into the cached effective-capabilities list.</li><li>Add the <code>plugins:self-manage</code> capability to the <code>Capability</code> union (grantable, not in any role preset by default).</li><li>Add Console grant/revoke UI on the user detail page, audited.</li><li>Wire RFC 0065&#39;s self-service opt-in to check <code>plugins:self-manage</code> via the per-user resolver.</li><li>Document the grant model and the &quot;custom role vs per-user grant&quot; guidance for operators.</li></ol><p>No <code>@sovereignfs/sdk</code> surface change is required beyond what RFC 0021 already ships (<code>hasCapability</code>/<code>requireCapability</code>); the per-user resolution happens server-side before capabilities reach the client. <code>runtime</code> gets a minor version bump for the new capability value and grant table.</p><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jul 2026</td><td>Initial draft — per-user capability grants as RFC 0021&#39;s deferred &quot;later phase,&quot; scoped to unblock RFC 0065 self-service plugin access.</td></tr></tbody></table>`,39)])])}const g=a(o,[["render",r]]);export{u as __pageData,g as default};
